from langchain.memory import ConversationBufferMemory
import re

class SecureMemory(ConversationBufferMemory):
    def save_context(self, inputs: Dict[str, Any], outputs: Dict[str, str]):
        # Sanitize before saving
        sanitized_input = self._sanitize(inputs['input'])
        sanitized_output = self._sanitize(outputs['output'])
        super().save_context(
            {'input': sanitized_input},
            {'output': sanitized_output}
        )

    def _sanitize(self, text: str) -> str:
        return re.sub(r'(sk-[A-Za-z0-9]{48}|[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,})', '[REDACTED]', text)

memory = SecureMemory()
